#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false); cin.tie(0);
    string x = "";
    string y = "";
    int T;
    cin >> T;
    for (int caseNo = 1; caseNo <= T; ++caseNo) {
        int N;
        cin >> N;
        cout << "Case #" << caseNo << ":";
        if (N == 1) {
            cout << " 0 1 5 6\n";
            continue;
        }
        string sx = x.substr(x.size() - N);
        string sy = y.substr(y.size() - N);
        vector<string> r;
        if (sx[0] != '0') r.push_back(sx);
        if (sy[0] != '0') r.push_back(sy);
        sort(r.begin(), r.end());
        if (r.empty()) cout << " Impossible\n";
        else for (const string& s : r) cout << ' ' << s;
        cout << '\n';
    }
    return 0;
}
